import React, { useState, useEffect, useMemo } from "react";
import axios from "axios";

function App() {
  const BASE_URL = "http://127.0.0.1:8000/api";

  const [expenses, setExpenses] = useState([]);
  const [title, setTitle] = useState("");
  const [amount, setAmount] = useState("");
  const [category, setCategory] = useState("Food");
  const [filter, setFilter] = useState("All");
  const [error, setError] = useState(null);

  // 👉 GET
  useEffect(() => {
    fetchExpenses();
  }, []);

  const fetchExpenses = async () => {
    setError(null);

    try {
      const res = await axios.get(`${BASE_URL}/expenses/`);
      setExpenses(res.data);
    } catch (err) {
      console.error("GET ERROR:", err);
      setError("Unable to load expenses.");
    }
  };

  // 👉 POST
  const addExpense = async (e) => {
    e.preventDefault();
    setError(null);

    // 🔥 VALIDATION
    const parsedAmount = Number(amount);
    if (!title || !amount || isNaN(parsedAmount)) {
      setError("Please enter a valid title and numeric amount.");
      return;
    }

    try {
      await axios.post(`${BASE_URL}/expenses/`, {
        title,
        amount: parsedAmount,
        category,
      });

      setTitle("");
      setAmount("");
      setCategory("");
      fetchExpenses();
    } catch (err) {
      console.error("POST ERROR:", err.response || err);

      if (err.response) {
        setError(
          `Unable to add expense: ${
            typeof err.response.data === "object"
              ? JSON.stringify(err.response.data)
              : err.response.data
          }`
        );
      } else {
        setError(`Unable to add expense: ${err.message}`);
      }
    }
  };

  // 👉 DELETE
  const deleteExpense = async (id) => {
    setError(null);

    try {
      await axios.delete(`${BASE_URL}/expenses/${id}/`);
      fetchExpenses();
    } catch (err) {
      console.error("DELETE ERROR:", err);
      setError("Unable to delete expense.");
    }
  };

  // 👉 TOTAL
  const total = useMemo(() => {
    return expenses.reduce((sum, exp) => sum + Number(exp.amount), 0);
  }, [expenses]);

  // 👉 FILTER
  const filteredExpenses =
    filter === "All"
      ? expenses
      : expenses.filter((exp) => exp.category === filter);

  return (
    <div style={{ padding: "20px", maxWidth: "500px", margin: "auto" }}>
      <h2>Expense Tracker</h2>

      {/* Error */}
      {error && (
        <div style={{ color: "red", marginBottom: "10px" }}>
          {error}
        </div>
      )}

      {/* Form */}
      <form onSubmit={addExpense} style={{ marginBottom: "15px" }}>
        <input
          placeholder="Title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          style={{ marginRight: "10px", padding: "5px" }}
        />

        <input
          placeholder="Amount"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
          style={{ marginRight: "10px", padding: "5px" }}
        />

        {/* 👉 CATEGORY DROPDOWN */}
        <select
          value={category}
          onChange={(e) => setCategory(e.target.value)}
          style={{ marginRight: "10px", padding: "5px" }}
        >
          <option value="">Select Category</option>
          <option value="Food">Food</option>
          <option value="Travel">Travel</option>
          <option value="Shopping">Shopping</option>
        </select>

        <button type="submit">Add</button>
      </form>

      <hr />

      {/* 👉 FILTER */}
      <select
        value={filter}
        onChange={(e) => setFilter(e.target.value)}
        style={{ marginBottom: "10px", padding: "5px" }}
      >
        <option value="All">All</option>
        <option value="Food">Food</option>
        <option value="Travel">Travel</option>
        <option value="Shopping">Shopping</option>
      </select>

      {/* 👉 TOTAL */}
      <h3>Total: ₹{total}</h3>

      {/* Expense List */}
      {filteredExpenses.length === 0 ? (
        <p>No expenses found.</p>
      ) : (
        filteredExpenses.map((exp) => (
          <div
            key={exp.id}
            style={{
              display: "flex",
              justifyContent: "space-between",
              padding: "8px",
              borderBottom: "1px solid #ccc",
            }}
          >
            <span>
              {exp.title} - ₹{exp.amount} ({exp.category})
            </span>

            <button onClick={() => deleteExpense(exp.id)}>
              Delete
            </button>
          </div>
        ))
      )}
    </div>
  );
}

export default App;
